use formo_ir::{IrProgram, Value};

pub(crate) fn render_css(ir: &IrProgram) -> String {
    format!("{}{}", base_css(), generate_style_rules(ir))
}

fn base_css() -> String {
    "/* generated by formo-backend-web */\n:root {\n  font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, sans-serif;\n  color: #151515;\n  background: #f6f7fb;\n}\n* { box-sizing: border-box; }\nbody { margin: 0; }\n#app { min-height: 100vh; padding: 16px; }\n.fm-window {\n  border: 1px solid #d4d8e5;\n  border-radius: 14px;\n  background: #ffffff;\n  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.07);\n  overflow: hidden;\n}\n.fm-window-title {\n  margin: 0;\n  padding: 12px 16px;\n  font-size: 16px;\n  border-bottom: 1px solid #e7e9f1;\n}\n.fm-page {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  padding: 12px;\n}\n.fm-row {\n  display: flex;\n  flex-direction: row;\n  gap: 8px;\n}\n.fm-column {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n.fm-stack, .fm-card, .fm-scroll {\n  display: block;\n}\n.fm-card {\n  border-radius: 10px;\n  border: 1px solid #d7dbe8;\n  background: #ffffff;\n  padding: 10px;\n}\n.fm-scroll {\n  overflow: auto;\n}\n.fm-text {\n  font-size: 16px;\n  line-height: 1.4;\n}\n.fm-image {\n  max-width: 100%;\n  height: auto;\n  display: block;\n}\n.fm-input {\n  border: 1px solid #b8bfd8;\n  border-radius: 8px;\n  padding: 8px 10px;\n  min-width: 220px;\n}\n.fm-button {\n  padding: 8px 12px;\n  border-radius: 8px;\n  border: 1px solid #b8bfd8;\n  background: #f4f7ff;\n  cursor: pointer;\n}\n.fm-button:disabled {\n  opacity: 0.6;\n  cursor: not-allowed;\n}\n.fm-check, .fm-switch {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n}\n.fm-switch-input {\n  width: 40px;\n  height: 20px;\n}\n.fm-spacer {\n  display: inline-block;\n}\n.fm-modal {\n  position: fixed;\n  inset: 0;\n  display: grid;\n  place-items: center;\n  z-index: 50;\n}\n.fm-modal.is-hidden {\n  display: none;\n}\n.fm-modal-backdrop {\n  position: absolute;\n  inset: 0;\n  background: rgba(0, 0, 0, 0.45);\n}\n.fm-modal-panel {\n  position: relative;\n  z-index: 1;\n  min-width: 280px;\n  max-width: 90vw;\n  max-height: 80vh;\n  overflow: auto;\n  border-radius: 12px;\n  background: #fff;\n  border: 1px solid #d7dbe8;\n  padding: 14px;\n  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.24);\n}\n.fm-modal-close {\n  margin-bottom: 10px;\n}\n.fm-node {\n  border: 1px dashed #c9cedf;\n  border-radius: 8px;\n  padding: 8px;\n}\n.fm-error {\n  color: #a80000;\n  background: #ffe9e9;\n  border: 1px solid #ffbcbc;\n  padding: 8px;\n  border-radius: 8px;\n}\n"
        .to_string()
}

fn generate_style_rules(ir: &IrProgram) -> String {
    let mut out = String::new();

    for style in &ir.styles {
        out.push('.');
        out.push_str(&style_id_to_class(&style.id));
        out.push_str(" {\n");

        for (key, value) in &style.decls {
            let css_prop = to_css_prop_name(key);
            let css_value = to_css_value(value);
            out.push_str("  ");
            out.push_str(&css_prop);
            out.push_str(": ");
            out.push_str(&css_value);
            out.push_str(";\n");
        }

        out.push_str("}\n");
    }

    out
}

fn style_id_to_class(style_id: &str) -> String {
    let mut out = String::from("fs-");
    for ch in style_id.chars() {
        if ch.is_ascii_alphanumeric() || ch == '_' || ch == '-' {
            out.push(ch);
        } else {
            out.push('-');
        }
    }
    out
}

fn to_css_prop_name(prop: &str) -> String {
    prop.to_string()
}

fn to_css_value(value: &Value) -> String {
    match value.t.as_str() {
        "color" | "string" => value.v.as_str().unwrap_or("").to_string(),
        "int" | "float" => value.v.to_string(),
        "bool" => {
            if value.v.as_bool().unwrap_or(false) {
                "true".to_string()
            } else {
                "false".to_string()
            }
        }
        "len" => {
            if let Some(obj) = value.v.as_object() {
                let val = obj
                    .get("value")
                    .map(|num| {
                        if let Some(i) = num.as_i64() {
                            i.to_string()
                        } else if let Some(f) = num.as_f64() {
                            if (f.fract()).abs() < f64::EPSILON {
                                (f as i64).to_string()
                            } else {
                                f.to_string()
                            }
                        } else {
                            "0".to_string()
                        }
                    })
                    .unwrap_or_else(|| "0".to_string());
                let unit = obj.get("unit").and_then(|v| v.as_str()).unwrap_or("px");
                let css_unit = if unit == "dp" { "px" } else { unit };
                format!("{val}{css_unit}")
            } else {
                value.v.to_string()
            }
        }
        _ => value.v.to_string(),
    }
}
